import React from 'react';
import MilestoneIcon from './MilestoneIcons';
export default function MilestoneCard({milestone}){
  const{label,date,noDate,status}=milestone;
  const cardCls={done:'bg-white border-[1.5px] border-ss-green/30 shadow-sm hover:border-ss-green/50 hover:shadow-md hover:-translate-y-0.5 transition-all',active:'bg-white border-2 border-ss-blue shadow-[0_0_0_4px_rgba(31,88,251,0.1),0_2px_12px_rgba(22,30,91,0.06)]',pending:'bg-white border-[1.5px] border-ss-border opacity-70'};
  const iconCls={done:'bg-ss-green/10 text-ss-green',active:'bg-ss-blue/[0.12] text-ss-blue',pending:'bg-gray-100 text-gray-300'};
  return(<div className={`rounded-xl p-4 relative cursor-default min-h-[120px] flex flex-col ${cardCls[status]}`}>
    <div className={`w-[30px] h-[30px] rounded-lg flex items-center justify-center mb-2 ${iconCls[status]}`}><div className="w-4 h-4"><MilestoneIcon label={label}/></div></div>
    {status==='done'&&<div className="absolute top-2.5 right-2.5 w-[18px] h-[18px] rounded-full bg-ss-green flex items-center justify-center"><svg viewBox="0 0 12 12" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" className="w-[10px] h-[10px]"><path d="M2.5 6l2.5 2.5 4.5-5"/></svg></div>}
    <div className={`text-[13px] leading-snug flex-1 ${status==='pending'?'text-gray-400 font-medium':'text-navy font-semibold'}`}>{label}</div>
    <div className="mt-2">
      {status==='done'&&(noDate||!date?<div className="text-[11px] font-semibold text-ss-green">Complete</div>:<div className="text-[11px] font-semibold text-ss-green">{date}</div>)}
      {status==='active'&&<div className="text-[11px] font-semibold text-ss-blue italic flex items-center gap-1.5"><span className="inline-block w-[7px] h-[7px] rounded-full bg-ss-blue animate-pulse-dot"/>In progress</div>}
      {status==='pending'&&<div className="text-[11px] text-gray-400 italic">Pending</div>}
    </div>
  </div>);
}
