import React from 'react';
function formatPhone(p){
  if(!p)return '';
  var d=p.replace(/[^\d+]/g,'');
  if(d.startsWith('+1')&&d.length===12){var n=d.slice(2);return '+1 ('+n.slice(0,3)+') '+n.slice(3,6)+'-'+n.slice(6);}
  if(d.startsWith('+506')&&d.length===12){var n=d.slice(4);return '+506 '+n.slice(0,4)+'-'+n.slice(4);}
  if(d.startsWith('+52')&&d.length===13){var n=d.slice(3);return '+52 ('+n.slice(0,3)+') '+n.slice(3,6)+'-'+n.slice(6);}
  return p;
}
function phoneFlag(p){if(!p)return '';var s=p.replace(/\s/g,'');if(s.startsWith('+506'))return '🇨🇷 ';if(s.startsWith('+1'))return '🇺🇸 ';if(s.startsWith('+52'))return '🇲🇽 ';return '';}
export default function ContactCard({role,name,email,phone,photo}){
  if(!name)return null;
  const initials=name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
  const displayPhone=formatPhone(phone);
  return(<div className="flex items-center gap-3 min-w-0 flex-1">
    {photo?<img src={photo} alt={name} className="w-10 h-10 rounded-full object-cover flex-shrink-0"/>:<div className="w-10 h-10 rounded-full bg-navy flex items-center justify-center text-white font-semibold text-xs flex-shrink-0">{initials}</div>}
    <div className="min-w-0 flex-1">
      <div className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">{role}</div>
      <div className="text-[13px] font-semibold text-navy truncate">{name}</div>
      <div className="flex flex-wrap gap-x-3 gap-y-0">
        {email&&<a href={'mailto:'+email} className="text-[11px] text-ss-blue hover:text-ss-blue-hover truncate">{email}</a>}
        {phone&&<a href={'tel:'+phone} className="text-[11px] text-ss-blue hover:text-ss-blue-hover">{phoneFlag(phone)}{displayPhone}</a>}
      </div>
    </div>
  </div>);
}
